/* {{pp-template}} */
.hover-highlight tr:hover,
.mw-datatable tr:hover {
  background-color: var(--background-color-progressive-subtle, #f1f4fd);
  color: var(--color-base, #202122);
}
.mw-datatable {
  background-color: var(--background-color-base, #fff);
  color: var(--color-base, #202122);
}

